-    // In practice, the pipeline calls compile() which produces both the
-    // ProjectionOutput and retains access to the local type. However,
-    // since ProjectionOutput doesn't carry the LocalType (it's rendered
-    // to a string), we re-project from the protocol in generate().
-    //
-    // This function is a placeholder; the actual local type is threaded
-    // through render_saga_module_from_local() below.
-    LocalType::End
-}
